previewCss:
.darma-loader-darma-custom-028 {
  width: 20px;
  aspect-ratio: 1;
  border-radius: 50%;
  position: relative;
  transform-origin: 50% -200%;
  background: radial-gradient(at 30% 30%, #0000, #000a) #ff0000;
  animation: darma-loader-darma-custom-028-l8 1s cubic-bezier(.5, -200, .5, 200) infinite;
}
.darma-loader-darma-custom-028:before {
  content: "";
  position: absolute;
  inset: -200% 8px 100%;
  background: #ddd;
}
@keyframes darma-loader-darma-custom-028-l8 {
  100% { transform: rotate(1deg); }
}

